import { test, expect } from "@playwright/test";
import identity from "../src/content/about/identity";
import { projects } from "../src/content/projects/index";

test("GET / returns 200", async ({ request }) => {
  const res = await request.get("/");
  expect(res.status()).toBe(200);
});

test("landing page h1 contains the user's name", async ({ page }) => {
  await page.goto("/");
  await expect(page.locator("h1")).toContainText(identity.name);
});

test("Ask my LLM about my work CTA points to /chat", async ({ page }) => {
  await page.goto("/");
  const link = page.getByRole("link", { name: /Ask my LLM about my work/i }).first();
  await expect(link).toBeVisible();
  await expect(link).toHaveAttribute("href", "/chat");
});

test("three project cards exist with titles for HVM, PRP, THS", async ({ page }) => {
  await page.goto("/");
  const hvm = projects.find((p) => p.code === "HVM")!;
  const prp = projects.find((p) => p.code === "PRP")!;
  const ths = projects.find((p) => p.code === "THS")!;
  await expect(page.getByRole("link", { name: new RegExp(hvm.title, "i") }).first()).toBeVisible();
  await expect(page.getByRole("link", { name: new RegExp(prp.title, "i") }).first()).toBeVisible();
  await expect(page.getByRole("link", { name: new RegExp(ths.title, "i") }).first()).toBeVisible();
});

test("Open the full chat link exists in ChatPreview section", async ({ page }) => {
  await page.goto("/");
  const link = page.getByRole("link", { name: /Open the full chat/i }).first();
  await expect(link).toBeVisible();
  await expect(link).toHaveAttribute("href", "/chat");
});

// Words and phrases that must not appear in chrome, button text, or
// marketing copy. The list mirrors the "What to avoid" section of
// docs/voice-guide.md. Long-form prose authored by Michael is exempt;
// the lint script excludes MDX bodies. A per-occurrence override is
// available via a /* voice-allow */ comment immediately preceding the
// offending string.
export const FORBIDDEN_WORDS = [
  // Corporate-speak
  "synergy",
  "ecosystem",
  "leverage", // verb sense; nouns covered by override comment
  "unlock",
  "unleash",
  "robust",
  "innovative",
  "thought-leader",
  "thought leader",
  "visionary",
  "disrupt",
  "disruption",
  "revolutionary",
  "game-changing",
  "game changing",
  "cutting-edge",
  "cutting edge",
  "seamless",
  "effortless",
  "empowering",
  "passionate",
  // Intensifier abuse
  "literally",
  // Hedges that erase the claim
  "perhaps maybe",
  "maybe possibly",
  "perhaps maybe possibly",
  "might potentially",
] as const;

export type ForbiddenWord = (typeof FORBIDDEN_WORDS)[number];

